def find_max_and_pair(nums):
    n = len(nums)
    if n < 2:
        return 0

    max_and_value = 0

    for i in range(n):
        for j in range(i + 1, n):
            current_and = nums[i] & nums[j]
            if current_and > max_and_value:
                max_and_value = current_and

    return max_and_value
